from collections import deque

class PushRelabel:
    def __init__(self, n):
        self.n = n
        self.capacity = [[0] * n for _ in range(n)]
        self.flow = [[0] * n for _ in range(n)]
        self.height = [0] * n
        self.excess = [0] * n
        self.adj = [[] for _ in range(n)]
        self.current_edge_idx = [0] * n

    def add_edge(self, u, v, cap):
        self.capacity[u][v] = cap
        self.adj[u].append(v)
        self.adj[v].append(u)

    def push(self, u, v, active_vertices_queue):
        send = min(self.excess[u], self.capacity[u][v] - self.flow[u][v])

        if send == 0:
            return False

        was_v_inactive = (self.excess[v] == 0)

        self.flow[u][v] += send
        self.flow[v][u] -= send

        self.excess[u] -= send
        self.excess[v] += send

        if was_v_inactive and self.excess[v] > 0 and v != self.s and v != self.t:
            active_vertices_queue.append(v)

        return True

    def relabel(self, u):
        min_height = float('inf')
        for v in self.adj[u]:
            if self.capacity[u][v] - self.flow[u][v] > 0:
                min_height = min(min_height, self.height[v])

        if min_height == float('inf'):
            return False

        self.height[u] = min_height + 1
        return True

    def push_relabel_max_flow(self, s, t):
        self.s = s
        self.t = t

        self.flow = [[0] * self.n for _ in range(self.n)]
        self.height = [0] * self.n
        self.excess = [0] * self.n
        self.current_edge_idx = [0] * self.n

        self.height[s] = self.n
        active_vertices = deque()

        for v in self.adj[s]:
            if self.capacity[s][v] > 0:
                delta = self.capacity[s][v]
                self.flow[s][v] += delta
                self.flow[v][s] -= delta
                self.excess[s] -= delta

                if v != self.s and v != self.t:
                    if self.excess[v] == 0:
                        active_vertices.append(v)
                    self.excess[v] += delta
                elif v == self.t:
                    self.excess[v] += delta

        while active_vertices:
            u = active_vertices.popleft()

            while self.excess[u] > 0:
                pushed_successfully_from_u = False
                while self.current_edge_idx[u] < len(self.adj[u]):
                    v = self.adj[u][self.current_edge_idx[u]]

                    if self.capacity[u][v] - self.flow[u][v] > 0 and self.height[u] > self.height[v]:
                        if self.push(u, v, active_vertices):
                            pushed_successfully_from_u = True
                            break

                    self.current_edge_idx[u] += 1

                if not pushed_successfully_from_u:
                    if self.relabel(u):
                        self.current_edge_idx[u] = 0
                        active_vertices.append(u)
                        break
                    else:
                        break

        return self.excess[t]
